sql:
SELECT username
FROM users
WHERE user_id IN (SELECT user_id FROM compliance_reports);

SELECT status, COUNT(*) as requirement_count
FROM compliance_requirements
GROUP BY status;

SELECT file_path
FROM compliance_documents
WHERE upload_date > '2023-01-01';

SELECT COUNT(*) AS active_alert_count
FROM compliance_alerts
WHERE status = 'active';

SELECT user_id, COUNT(*) as notification_count
FROM compliance_notifications
GROUP BY user_id;

SELECT MAX(duration_days) AS max_duration_days
FROM compliance_requirements
WHERE status = 'active';

SELECT COUNT(*) AS total_active_alerts
FROM compliance_alerts
WHERE status = 'active';
